                let _ = self.writer.emit(V2AuditEventKind::ToolDenied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
                *self.tripped.lock().expect("tripped mutex") = Some(EnforcementDecision::Denied {
                    tool_name: tool_name.clone(),
                    reason: reason.clone(),
                });
