127	pub struct InMemorySink {
128	    events: Mutex<Vec<LoopAuditEvent>>,
129	    blobs: Mutex<Vec<(String, Vec<u8>)>>,
130	    blob_store: BlobStore,
131	}
132	
133	impl InMemorySink {
134	    pub fn new(blob_root: impl Into<PathBuf>) -> Self {
135	        Self {
136	            events: Mutex::new(Vec::new()),
137	            blobs: Mutex::new(Vec::new()),
138	            blob_store: BlobStore::new(blob_root),
139	        }
140	    }
141	
142	    pub fn events(&self) -> Vec<LoopAuditEvent> {
143	        self.events.lock().expect("audit mutex").clone()
144	    }
145	
146	    pub fn blob_store(&self) -> &BlobStore {
147	        &self.blob_store
148	    }
149	}
150	
151	impl AuditSink for InMemorySink {
152	    fn emit(&self, event: &LoopAuditEvent) {
153	        self.events.lock().expect("audit mutex").push(event.clone());
154	    }
155	    fn write_blob(&self, content: &[u8]) -> String {
156	        let hash = self
157	            .blob_store
158	            .write(content)
159	            .unwrap_or_else(|err| format!("error:{err}"));
160	        self.blobs
161	            .lock()
162	            .expect("blob mutex")
163	            .push((hash.clone(), content.to_vec()));
164	        hash
165	    }
166	}
